import asyncio
import json
import logging
import signal
import uuid
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any

import websockets
from websockets.server import WebSocketServerProtocol


logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(name)s: %(message)s",
)
logger = logging.getLogger("mmo-server")


@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str


@dataclass
class Player:
    player_id: str
    websocket: WebSocketServerProtocol
    inventory: Set[str] = field(default_factory=set)
    lock: asyncio.Lock = field(default_factory=asyncio.Lock)


class GameState:
    def __init__(self) -> None:
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.players_lock = asyncio.Lock()
        self.items_lock = asyncio.Lock()

    async def add_player(self, player_id: str, websocket: WebSocketServerProtocol) -> Player:
        async with self.players_lock:
            if player_id in self.players:
                raise ValueError(f"player already connected: {player_id}")
            player = Player(player_id=player_id, websocket=websocket)
            self.players[player_id] = player
            return player

    async def remove_player(self, player_id: str) -> None:
        async with self.players_lock:
            self.players.pop(player_id, None)

    async def get_player(self, player_id: str) -> Optional[Player]:
        async with self.players_lock:
            return self.players.get(player_id)

    async def create_item(self, owner_id: str, name: str) -> Item:
        async with self.items_lock:
            item_id = str(uuid.uuid4())
            item = Item(item_id=item_id, name=name, owner_id=owner_id)
            self.items[item_id] = item
        player = await self.get_player(owner_id)
        if player is None:
            raise ValueError("owner not found")
        async with player.lock:
            player.inventory.add(item_id)
        return item

    async def get_item(self, item_id: str) -> Optional[Item]:
        async with self.items_lock:
            return self.items.get(item_id)

    async def list_inventory(self, player_id: str) -> Dict[str, Any]:
        player = await self.get_player(player_id)
        if player is None:
            raise ValueError("player not found")
        async with player.lock:
            item_ids = list(player.inventory)
        async with self.items_lock:
            items = [
                {
                    "item_id": item.item_id,
                    "name": item.name,
                    "owner_id": item.owner_id,
                }
                for iid in item_ids
                if (item := self.items.get(iid)) is not None
            ]
        return {"player_id": player_id, "items": items}

    async def transfer_item(self, from_player_id: str, to_player_id: str, item_id: str) -> Dict[str, Any]:
        if from_player_id == to_player_id:
            raise ValueError("cannot transfer item to self")

        from_player = await self.get_player(from_player_id)
        to_player = await self.get_player(to_player_id)

        if from_player is None or to_player is None:
            raise ValueError("source or destination player not found")

        first, second = sorted([from_player, to_player], key=lambda p: p.player_id)

        async with first.lock:
            async with second.lock:
                async with self.items_lock:
                    item = self.items.get(item_id)
                    if item is None:
                        raise ValueError("item not found")
                    if item.owner_id != from_player_id:
                        raise ValueError("item is not owned by source player")
                    if item_id not in from_player.inventory:
                        raise ValueError("item missing from source inventory")

                    from_player.inventory.remove(item_id)
                    to_player.inventory.add(item_id)
                    item.owner_id = to_player_id

                    return {
                        "item_id": item.item_id,
                        "name": item.name,
                        "from_player_id": from_player_id,
                        "to_player_id": to_player_id,
                    }


class MMOServer:
    def __init__(self, host: str = "0.0.0.0", port: int = 8765) -> None:
        self.host = host
        self.port = port
        self.state = GameState()
        self.stop_event = asyncio.Event()

    async def send(self, websocket: WebSocketServerProtocol, message: Dict[str, Any]) -> None:
        await websocket.send(json.dumps(message))

    async def broadcast_inventory(self, player_id: str) -> None:
        player = await self.state.get_player(player_id)
        if player is None:
            return
        inventory = await self.state.list_inventory(player_id)
        await self.send(player.websocket, {"type": "inventory", "data": inventory})

    async def notify_trade(self, from_player_id: str, to_player_id: str, trade_data: Dict[str, Any]) -> None:
        from_player = await self.state.get_player(from_player_id)
        to_player = await self.state.get_player(to_player_id)

        payload = {"type": "trade_complete", "data": trade_data}

        if from_player is not None:
            await self.send(from_player.websocket, payload)
            await self.broadcast_inventory(from_player_id)

        if to_player is not None:
            await self.send(to_player.websocket, payload)
            await self.broadcast_inventory(to_player_id)

    async def handle_message(self, player: Player, message: Dict[str, Any]) -> None:
        action = message.get("action")
        request_id = message.get("request_id")

        try:
            if action == "create_item":
                name = message["name"]
                item = await self.state.create_item(player.player_id, name)
                await self.send(
                    player.websocket,
                    {
                        "type": "create_item_result",
                        "request_id": request_id,
                        "ok": True,
                        "item": {
                            "item_id": item.item_id,
                            "name": item.name,
                            "owner_id": item.owner_id,
                        },
                    },
                )
                await self.broadcast_inventory(player.player_id)

            elif action == "inventory":
                inventory = await self.state.list_inventory(player.player_id)
                await self.send(
                    player.websocket,
                    {
                        "type": "inventory_result",
                        "request_id": request_id,
                        "ok": True,
                        "data": inventory,
                    },
                )

            elif action == "trade_item":
                to_player_id = message["to_player_id"]
                item_id = message["item_id"]
                trade_data = await self.state.transfer_item(player.player_id, to_player_id, item_id)
                await self.send(
                    player.websocket,
                    {
                        "type": "trade_item_result",
                        "request_id": request_id,
                        "ok": True,
                        "data": trade_data,
                    },
                )
                await self.notify_trade(player.player_id, to_player_id, trade_data)

            elif action == "admin_grant_item":
                owner_id = message["owner_id"]
                name = message["name"]
                item = await self.state.create_item(owner_id, name)
                owner = await self.state.get_player(owner_id)
                if owner is not None:
                    await self.send(
                        player.websocket,
                        {
                            "type": "admin_grant_item_result",
                            "request_id": request_id,
                            "ok": True,
                            "item": {
                                "item_id": item.item_id,
                                "name": item.name,
                                "owner_id": item.owner_id,
                            },
                        },
                    )
                    await self.broadcast_inventory(owner_id)
                else:
                    raise ValueError("owner not found")

            else:
                raise ValueError("unknown action")

        except KeyError as e:
            await self.send(
                player.websocket,
                {
                    "type": "error",
                    "request_id": request_id,
                    "ok": False,
                    "error": f"missing field: {e.args[0]}",
                },
            )
        except Exception as e:
            await self.send(
                player.websocket,
                {
                    "type": "error",
                    "request_id": request_id,
                    "ok": False,
                    "error": str(e),
                },
            )

    async def authenticate(self, websocket: WebSocketServerProtocol) -> Player:
        raw = await asyncio.wait_for(websocket.recv(), timeout=15)
        try:
            message = json.loads(raw)
        except json.JSONDecodeError:
            raise ValueError("invalid json")

        if message.get("action") != "login":
            raise ValueError("first message must be login")

        player_id = message.get("player_id")
        if not player_id or not isinstance(player_id, str):
            raise ValueError("invalid player_id")

        player = await self.state.add_player(player_id, websocket)
        await self.send(
            websocket,
            {
                "type": "login_result",
                "ok": True,
                "player_id": player_id,
            },
        )
        return player

    async def handler(self, websocket: WebSocketServerProtocol) -> None:
        player: Optional[Player] = None
        try:
            player = await self.authenticate(websocket)
            logger.info("player connected: %s", player.player_id)
            await self.broadcast_inventory(player.player_id)

            async for raw in websocket:
                try:
                    message = json.loads(raw)
                except json.JSONDecodeError:
                    await self.send(
                        websocket,
                        {
                            "type": "error",
                            "ok": False,
                            "error": "invalid json",
                        },
                    )
                    continue

                await self.handle_message(player, message)

        except Exception as e:
            logger.info("connection error: %s", e)
            try:
                await self.send(
                    websocket,
                    {
                        "type": "error",
                        "ok": False,
                        "error": str(e),
                    },
                )
            except Exception:
                pass
        finally:
            if player is not None:
                await self.state.remove_player(player.player_id)
                logger.info("player disconnected: %s", player.player_id)

    async def run(self) -> None:
        async with websockets.serve(self.handler, self.host, self.port, ping_interval=20, ping_timeout=20):
            logger.info("server running on %s:%s", self.host, self.port)
            await self.stop_event.wait()

    def stop(self) -> None:
        self.stop_event.set()


async def main() -> None:
    server = MMOServer()

    loop = asyncio.get_running_loop()
    for sig in (signal.SIGINT, signal.SIGTERM):
        try:
            loop.add_signal_handler(sig, server.stop)
        except NotImplementedError:
            pass

    await server.run()


if __name__ == "__main__":
    asyncio.run(main())